// Pega o texto bruto vindo do LLM
let rawText = $input.item.json.output || $input.item.json.text; 

if (typeof rawText === 'string') {
  try {
    // 1. Limpa espaços em branco no início/fim e caracteres de controle invisíveis
    const cleanText = rawText.trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, "");

    // 2. Tenta o parse direto
    const messagesArray = JSON.parse(cleanText);

    return {
      mensagens_formatadas: Array.isArray(messagesArray) ? messagesArray : [messagesArray]
    };
  } catch (e) {
    // 3. Fallback: Se falhar (como no erro do token '\'), tenta limpar aspas extras
    try {
        // Remove possíveis quebras de linha literais que quebram o parser
        const secondaryClean = rawText.replace(/\n/g, " "); 
        return {
            mensagens_formatadas: [JSON.parse(secondaryClean)]
        };
    } catch (e2) {
        // Se tudo falhar, retorna o texto bruto dentro de um array para o WhatsApp não quebrar
        return {
          mensagens_formatadas: [rawText],
          erro_original: e.message
        };
    }
  }
}

return {
  mensagens_formatadas: [rawText]
};

let redisValue = $('Pega o bloqueioBot').first().json.bloqueioBot;
let agora = new Date();
let horarioExpiracao = null;

if (redisValue && typeof redisValue === 'string') {
    horarioExpiracao = new Date(redisValue);
}

if (horarioExpiracao && !isNaN(horarioExpiracao.getTime()) && horarioExpiracao > agora) {
    // SOMA: Adiciona 3 minutos (180.000ms)
    let novoHorario = new Date(horarioExpiracao.getTime() + 180000); 

    // Calcula o TTL inicial em segundos
    let novoTTL = Math.round((novoHorario.getTime() - agora.getTime()) / 1000);

    // --- TRAVA DE SEGURANÇA: MÁXIMO 1 HORA (3600 segundos) ---
    if (novoTTL > 3600) {
        novoTTL = 3600;
        // Ajustamos o novo_valor para ser exatamente daqui a 1 hora
        novoHorario = new Date(agora.getTime() + 3600000);
    }
    // ---------------------------------------------------------

    return {
        novo_valor: novoHorario.toISOString(),
        novo_ttl: novoTTL,
        status: "SOMANDO_COM_LIMITE"
    };
} else {
    // INÍCIO: 10 minutos (600s)
    let expiraEm = new Date(agora.getTime() + 600000); 
    return {
        novo_valor: expiraEm.toISOString(),
        novo_ttl: 3600,
        status: "NOVO_BLOQUEIO"
    };
}

// Pega os dados do nó de entrada (Webhook)
const data = $('Webhook').first().json.body.data;

// Extrai o identificador da conversa (pode ser o LID ou o próprio JID)
const remoteJid = data.key?.remoteJid || data.remoteJid;

return {
  lidKey: `Atendimento GTV_${remoteJid}_bloqueado`
};
